constexpr std::uint8_t bidi_mirroring_hex_nibble(char value) noexcept {
    return value >= '0' && value <= '9'
        ? static_cast<std::uint8_t>(value - '0')
        : static_cast<std::uint8_t>(value - 'a' + 10);
}

constexpr std::uint8_t bidi_mirroring_hex_byte(std::size_t byte_offset) noexcept {
    const std::size_t offset = byte_offset * 2U;
    return static_cast<std::uint8_t>(
        (bidi_mirroring_hex_nibble(kUnicodeBidiMirroringPackedHex[offset]) << 4U) |
        bidi_mirroring_hex_nibble(kUnicodeBidiMirroringPackedHex[offset + 1U]));
}

constexpr std::uint32_t bidi_mirroring_u32(std::size_t byte_offset) noexcept {
    return static_cast<std::uint32_t>(bidi_mirroring_hex_byte(byte_offset)) |
           (static_cast<std::uint32_t>(bidi_mirroring_hex_byte(byte_offset + 1U)) << 8U) |
           (static_cast<std::uint32_t>(bidi_mirroring_hex_byte(byte_offset + 2U)) << 16U) |
           (static_cast<std::uint32_t>(bidi_mirroring_hex_byte(byte_offset + 3U)) << 24U);
}

constexpr std::array<BidiMirroredRange, 114> decode_bidi_mirrored_ranges() noexcept {
    std::array<BidiMirroredRange, 114> output{};
    for (std::size_t index = 0U; index < output.size(); ++index) {
        const std::size_t offset = index * 8U;
        output[index] = BidiMirroredRange{
            bidi_mirroring_u32(offset),
            bidi_mirroring_u32(offset + 4U)};
    }
    return output;
}

constexpr std::array<BidiMirroringGlyphRecord, 428> decode_bidi_mirroring_glyphs() noexcept {
    std::array<BidiMirroringGlyphRecord, 428> output{};
    constexpr std::size_t kMappingOffset = 114U * 8U;
    for (std::size_t index = 0U; index < output.size(); ++index) {
        const std::size_t offset = kMappingOffset + index * 9U;
        output[index] = BidiMirroringGlyphRecord{
            bidi_mirroring_u32(offset),
            bidi_mirroring_u32(offset + 4U),
            bidi_mirroring_hex_byte(offset + 8U) != 0U};
    }
    return output;
}

inline constexpr auto kUnicodeBidiMirroredRanges = decode_bidi_mirrored_ranges();
inline constexpr auto kUnicodeBidiMirroringGlyphs = decode_bidi_mirroring_glyphs();

static_assert(kUnicodeBidiMirroringPackedHex.size() == (114U * 8U + 428U * 9U) * 2U);
static_assert(kUnicodeBidiMirroredRanges.front().first == 0x28U);
static_assert(kUnicodeBidiMirroredRanges.back().last == 0x1D7C3U);
static_assert(kUnicodeBidiMirroringGlyphs.front().codepoint == 0x28U);
static_assert(kUnicodeBidiMirroringGlyphs.back().codepoint == 0xFF63U);

